parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const cn = body.cert_subject_cn || (body.cert_subject_dn && body.cert_subject_dn.replace(/^.*CN=([^,]+).*$/i, '$1').trim()) || '';
const uid = body.uid || cn.replace(/[^a-zA-Z0-9._-]/g, '_') || 'pending';
if (!body.cert_fingerprint && !body.cert_subject_cn && !cn) {
  throw new Error('Missing cert_fingerprint or cert_subject_cn');
}
const level = ['admin','operator','developer','viewer','auditor'].includes(body.requested_privilege_level) ? body.requested_privilege_level : 'viewer';
return [{ json: {
  cert_fingerprint: body.cert_fingerprint || '',
  cert_subject_dn: body.cert_subject_dn || '',
  cert_subject_cn: body.cert_subject_cn || cn,
  uid,
  requested_privilege_level: level,
  email: body.email || `${uid}@local`,
  cn: body.cn || cn,
  created_at: new Date().toISOString(),
  registration_state: 'pending'
} }];

parameters.jsonBody:
={{ JSON.stringify({
  title: 'Approve certificate registration: ' + ($json.cert_subject_cn || $json.uid),
  group: 'Users',
  customer: $json.email,
  article: {
    subject: 'Cert registration: ' + $json.uid,
    body: 'Certificate-based self-registration. No privileges until this ticket is approved.\n\n' +
      'uid: ' + $json.uid + '\n' +
      'requested_privilege_level: ' + $json.requested_privilege_level + '\n' +
      'cert_subject_cn: ' + $json.cert_subject_cn + '\n' +
      'cert_fingerprint: ' + ($json.cert_fingerprint || 'n/a') + '\n' +
      'email: ' + $json.email + '\n' +
      'created_at: ' + $json.created_at + '\n\n' +
      'Payload (for approval workflow): ' + JSON.stringify($json)
  }
}) }}

parameters.responseBody:
={{ JSON.stringify({
  status: 'pending',
  message: 'No privileges granted until a human approves the ticket.',
  ticket_id: $json.id,
  ticket_url: ($env.ZAMMAD_URL || 'http://zammad') + '/#ticket/zoom/' + $json.id
}) }}
